algorithm:
Modified greedy insertion with time-window slack scoring: evaluate all feasible routes using a weighted cost-delta heuristic that penalizes tight time windows and rewards spatial proximity, then insert into the best feasible route; if none feasible, create a new assign at the first unused slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for oIdx := 0; oIdx < orderCount; oIdx++ {
		ori := oris[oIdx]
		des := dess[oIdx]
		shipID := total_ship + oIdx
		bestScore := 1e308
		bestAssignIdx := -1

		maxChecks := dispatch.AssignsLen
		for tryIdx := 0; tryIdx < maxChecks; tryIdx++ {
			a := &dispatch.Assigns[tryIdx]
			oldCost := a.Cost
			if a.AddShip(shipID, ori, des) {
				a.GenRoute()
				newCost := a.Cost
				delta := newCost - oldCost
				timeSlackPenalty := 0.0
				if ori.TimeEnd > ori.TimeStart {
					windowWidth := float64(ori.TimeEnd - ori.TimeStart)
					proximityWeight := 0.5
					spatialPenalty := cal_dis(a.StationCurrent, ori) * proximityWeight
					timeSlackPenalty = (windowWidth / (1.0 + windowWidth)) * 10.0 + spatialPenalty
				}
				score := delta*1.2 + timeSlackPenalty
				if score < bestScore && newCost >= 0 {
					bestScore = score
					bestAssignIdx = tryIdx
				}
				a.RemoveShip(shipID)
				a.GenRoute()
			}
		}

		nextEmptyIdx := dispatch.AssignsLen
		if nextEmptyIdx < MAXASSIGNS {
			emptyBaseCost := cal_dis(Station{}, ori) + cal_dis(ori, des)
			timeSlackPenalty := 0.0
			if ori.TimeEnd > ori.TimeStart {
				windowWidth := float64(ori.TimeEnd - ori.TimeStart)
				timeSlackPenalty = (windowWidth / (1.0 + windowWidth)) * 8.0
			}
			emptyScore := emptyBaseCost*1.0 + timeSlackPenalty
			if emptyScore < bestScore {
				bestScore = emptyScore
				bestAssignIdx = nextEmptyIdx
			}
		}

		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			target := &dispatch.Assigns[bestAssignIdx]
			if target.AddShip(shipID, ori, des) {
				target.GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = bestAssignIdx + 1
				}
			}
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				target := &dispatch.Assigns[fallbackIdx]
				if target.AddShip(shipID, ori, des) {
					target.GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

